local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("canMoveTo", function(player, xn, yn, zn) if not player or not xn or not zn then return end return TD.moveableterrian(player, xn, 0, zn) end) TD.createFn("moveableterrian", function(player, bx, by, bz) if not TD.valid(player) then return false end local ax, ay, az = TD.pos_g(player) local ground = TD.GetWorld() local btile = ground.Map:GetTileAtPoint(bx, by, bz) return TD.similarterrian(ground.Map:GetTileAtPoint(ax, 0, az), btile) end) TD.createFn("similarterrian", function(atile, btile) return not (atile == _G.GROUND.IMPASSABLE or btile == _G.GROUND.IMPASSABLE) end) TD.createFn("dist", function(x1, x2, z1, z2) if not x1 or not x2 or not z1 or not z2 then return 65535 end local dist = math.sqrt((x1 - x2) * (x1 - x2) + (z1 - z2) * (z1 - z2)) return dist end) TD.createFn("distBetween", function(target1, target2) if not target2 then target2 = TD.GetPlayer() end if not target1 or not target2 or not target1.Transform or not target2.Transform then return 65535 end local x1, y1, z1 = target1.Transform:GetWorldPosition() local x2, y2, z2 = target2.Transform:GetWorldPosition() return TD.dist(x1, x2, z1, z2) end) TD.createFn("stopMove", function(inst) if not inst then return end if inst.components.playercontroller then inst.components.playercontroller:Enable(false) end if inst.components.locomotor then inst.components.locomotor:Stop() inst.components.locomotor:Clear() end if inst.Physics and inst.Physics.ClearMotorVelOverride then inst.Physics:ClearMotorVelOverride() end if inst.Physics and inst.Physics.Stop then inst.Physics:Stop() end inst:ClearBufferedAction() end) TD.createFn("resetY", function(inst) if not inst then return end if not TD.valid(inst) then return end local x, y, z = TD.pos_g(inst) TD.pos_s(inst, x, 0, z) end) TD.createFn("find", function(target, dist) local x2, y2, z2 = target.Transform:GetWorldPosition() local ents = TheSim:FindEntities(x2, y2, z2, dist) return ents end) TD.createFn("findTag", function(target, dist, tag) local x2, y2, z2 = target.Transform:GetWorldPosition() local ents = TheSim:FindEntities(x2, y2, z2, dist, { tag }) return ents end) TD.createFn("aroundLiver", function(target, dist) local x2, y2, z2 = target.Transform:GetWorldPosition() local ents = TheSim:FindEntities(x2, y2, z2, dist) local result = {} TD.fori(ents, function(k, v) if TD.live(v) then result[k] = v end end) return result end) TD.createFn("valid", function(target) if not target then return false end if not target.IsValid or not target:IsValid() then return false end return true end) TD.createFn("pos_g", function(target) if not target then return 0, 0, 0 end if not target.IsValid or not target:IsValid() then return 0, 0, 0 end if not target.GetPosition then return 0, 0, 0 end return target:GetPosition():Get() end) TD.createFn("pos_s", function(target, x, y, z) if not target then return target end if not target.IsValid or not target:IsValid() then return target end if not target.Transform or not target.Transform.SetPosition then return target end local xo, yo, zo = TD.pos_g(target) if not TD.isNum(x) then x = xo end if not TD.isNum(y) then y = yo end if not TD.isNum(z) then z = zo end target.Transform:SetPosition(x, y, z) return target end) TD.createFn("pos_d", function(target, dx, dy, dz) if not target then return target end if not target.IsValid or not target:IsValid() then return target end if not target.Transform or not target.Transform.SetPosition then return target end local xo, yo, zo = TD.pos_g(target) if not TD.isNum(dx) then dx = 0 end if not TD.isNum(dy) then dy = 0 end if not TD.isNum(dz) then dz = 0 end local x = xo + dx local y = yo + dy local z = zo + dz return TD.pos_s(target, x, y, z) end) TD.createFn("rotation_g", function(target) if not target then return 0 end if not target.IsValid or not target:IsValid() then return 0 end if not target.Transform or not target.Transform.GetRotation then return 0 end return target.Transform:GetRotation() or 0 end) TD.createFn("below2", function(player, target) return TD.pos_s(target, TD.pos_g(player)) end) TD.createFn("pos", function(...) return TD.pos_g(...) end) TD.createFn("away", function(player, target, distance) if not player or not target then return end local x1, y1, z1 = TD.pos_g(player) local x2, y2, z2 = TD.pos_g(target) local angel = math.atan2(z1 - z2, x1 - x2) * (180 / math.pi) * _G.DEGREES local xp = (x2 - x1) / math.abs(x1 - x2) local zp = (z2 - z1) / math.abs(z1 - z2) local xadd = xp * math.abs(math.cos(angel) * distance) local zadd = zp * math.abs(math.sin(angel) * distance) if not TD.isNum(xadd) then xadd = 0 end if not TD.isNum(zadd) then zadd = 0 end return TD.pos_d(target, xadd, 0, zadd) end) TD.createFn("moveTo", function(targetFrom, targetTo, time, times) if not targetFrom or not targetTo then return end local times = times or 10 time = time or 1 local x1, y1, z1 = TD.pos_g(targetFrom) local x2, y2, z2 = TD.pos_g(targetTo) local xp = (x2 - x1) / times / 2 local yp = (y2 - y1) / times / 2 local zp = (z2 - z1) / times / 2  local deltaT = time / times TD.period(targetFrom, nil, function() TD.pos_d(targetFrom, xp, yp, zp) end, deltaT, time) end) TD.createFn("away2", function(player, target, distance) if not player or not target then return end local angle = TD.rotation_g(player) * _G.DEGREES local fin_x, fin_y, fin_z = distance * math.cos(angle), 0, -distance * math.sin(angle) local x0, y0, z0 = TD.pos_g(target) return TD.pos_s(target, x0 + fin_x, 0, z0 + fin_z) end) TD.createFn("away3", function(player, target, distance) if not player or not target then return end local angle = TD.rotation_g(target) * _G.DEGREES local fin_x, fin_y, fin_z = distance * math.cos(angle), 0, -distance * math.sin(angle) local x0, y0, z0 = TD.pos_g(target) return TD.pos_s(target, x0 + fin_x, 0, z0 + fin_z) end) TD.createFn("validAway", function(player, distance) if not player or not TD.isNum(distance) then return false end local angle = TD.rotation_g(player) * _G.DEGREES local fin_x, fin_y, fin_z = distance * math.cos(angle), 0, -distance * math.sin(angle) local x0, y0, z0 = TD.pos_g(player)  return TD.canMoveTo(player, x0 + fin_x, 0, z0 + fin_z) end) TD.createFn("backUpCurrentPt", function(player) if not player or not TD.server() then return end local x0, y0, z0 = TD.pos_g(player) player["backUpCurrentPt_x"] = x0 player["backUpCurrentPt_z"] = z0 end) local RESET_TASK_NAME = "td1madao_global_resetCurrentPt" TD.createFn("ResetCurrentPt", function(player, time) if not player or not TD.server() then return end  TD.removeTask(player, RESET_TASK_NAME) player[RESET_TASK_NAME] = TD.latter(player, time or 1, function() local ax, ay, az = TD.pos_g(player) local ground = TD.GetWorld() if ground.Map:GetTileAtPoint(ax, 0, az) == _G.GROUND.IMPASSABLE and TD.isNum(player["backUpCurrentPt_x"]) and TD.isNum(player["backUpCurrentPt_z"]) then local distance = 5 local placeSafe = false  TD.fori(20, function() local calcx = ax + math.random(distance) * TD.zf() local calcz = az + math.random(distance) * TD.zf() if ground.Map:GetTileAtPoint(calcx, 0, calcz) ~= _G.GROUND.IMPASSABLE then TD.pos_s(player, calcx, 0, calcz) placeSafe = true return true end end)  if not placeSafe then TD.pos_s(player, player["backUpCurrentPt_x"], 0, player["backUpCurrentPt_z"]) end end end) end) 